t.script:

let isEditMode = false;
let originalFormData = {};

// ---- Fields that portal user is ALLOWED to edit ----
// Add/remove field names here to control what employees can self-update.
const EDITABLE_FIELDS = [
  'private_email', 'private_phone', 'private_street', 'private_street2',
  'private_city', 'private_zip', 'emergency_contact', 'emergency_phone',
  'x_emirates_id', 'x_emirates_expiry', 'x_passport_number', 'x_passport_country',
  'x_passport_issue', 'x_passport_expiry',
  'whatsapp', 'linkedin', 'facebook_profile', 'insta_profile', 'twitter_profile',
  'house_no', 'area_name', 'zip_code',
  'emergency_contact_person_name', 'emergency_contact_person_phone',
  'emergency_contact_person_name_1', 'emergency_contact_person_phone_1',
  'home_land_line_no', 'country_code_for_personal_mob_no',
  'employee_first_name', 'employee_middle_name', 'employee_last_name',
  'employee_name_arabic', 'place_of_birth', 'birthday',
  'emirates_id_number', 'emirates_issue_date', 'emirates_expiry_date',
  'issue_date', 'spouse_support_no', 'spouse_passport_issue_date',
  'spouse_passport_expiry_date', 'spouse_visa_no', 'spouse_visa_expire_date',
  'spouse_emirates_id_no', 'spouse_emirates_issue_date', 'spouse_emirates_id_expiry_date',
  'dependent_child_name_1', 'dependent_child_dob_1',
  'dependent_child_passport_no', 'dependent_child_visa_no_1',
  'aadhar_no', 'pan', 'blooad_group', 'religion',
  'employee_nominee_name', 'employee_nominee_contact_no',
  'u_private_street', 'e_private_street',
];

// ---- Read-only fields (HR / system managed) ----
const READONLY_FIELDS = [
  'work_email', 'emp_code', 'employee_name_english', 'nationality_at_birth_id',
  'company_id', 'department_id', 'job_id', 'job_title', 'parent_id',
  'doj', 'original_hire_date', 'resign_date', 'end_date', 'lwd',
  'employement_status_id', 'exit_type_id', 'exit_reason_id',
  'practice', 'sub_practice', 'practice_heads_id', 'mentor_names_id',
  'contract_date_start', 'wage_type', 'wage', 'contract_type_id',
];

function toggleEditMode() {
  const editMode = document.getElementById('editMode').checked;
  if (editMode) { enableEditMode(); } else { disableEditMode(); }
}

function enableEditMode() {
  isEditMode = true;
  document.getElementById('editMode').checked = true;
  storeOriginalFormData();

  // Enable only allowed editable fields
  EDITABLE_FIELDS.forEach(name => {
    const els = document.querySelectorAll(`[name="${name}"]`);
    els.forEach(el => {
      el.removeAttribute('readonly');
      el.removeAttribute('disabled');
    });
  });

  // Enable file inputs
  document.querySelectorAll('input[type="file"]').forEach(el => {
    el.removeAttribute('disabled');
  });

  document.getElementById('formActions').style.display = 'block';
  document.getElementById('viewActions').style.display = 'none';

  // Add live validation listeners
  document.querySelectorAll('#personalDetailsForm input[data-validation], #personalDetailsForm select[data-validation]').forEach(input => {
    input.addEventListener('input', validateField);
    input.addEventListener('blur', validateField);
  });
}

function disableEditMode() {
  isEditMode = false;
  document.getElementById('editMode').checked = false;

  const inputs = document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select, #personalDetailsForm textarea');
  inputs.forEach(input => {
    if (input.type !== 'hidden') {
      input.setAttribute('readonly', 'readonly');
      if (input.tagName === 'SELECT' || input.type === 'file') {
        input.setAttribute('disabled', 'disabled');
      }
    }
  });

  document.getElementById('formActions').style.display = 'none';
  document.getElementById('viewActions').style.display = 'block';
  clearValidationStates();
}

function storeOriginalFormData() {
  const form = document.getElementById('personalDetailsForm');
  const formData = new FormData(form);
  originalFormData = {};
  for (let [key, value] of formData.entries()) {
    originalFormData[key] = value;
  }
}

function cancelEdit() {
  for (let [key, value] of Object.entries(originalFormData)) {
    const input = document.querySelector(`[name="${key}"]`);
    if (input) { input.value = value; }
  }
  disableEditMode();
  showMessage('Changes cancelled.', 'info');
}

function saveAsDraft() {
  const form = document.getElementById('personalDetailsForm');
  const formData = new FormData(form);
  const draftData = {};
  for (let [key, value] of formData.entries()) { draftData[key] = value; }
  localStorage.setItem('profileDraft', JSON.stringify(draftData));
  showMessage('Profile saved as draft.', 'info');
}

function validateField(event) {
  const field = event.target;
  const validationType = field.getAttribute('data-validation');
  let isValid = true;
  let errorMessage = '';

  field.classList.remove('is-valid', 'is-invalid');

  if (validationType) {
    switch (validationType) {
      case 'email':
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (field.value && !emailRegex.test(field.value)) {
          isValid = false; errorMessage = 'Please enter a valid email address.';
        }
        break;
      case 'phone':
        const phoneRegex = /^[+]?[0-9\s\-\(\)]+$/;
        if (field.value && !phoneRegex.test(field.value)) {
          isValid = false; errorMessage = 'Please enter a valid phone number.';
        }
        break;
      case 'required':
        if (!field.value || field.value.trim() === '') {
          isValid = false; errorMessage = 'This field is required.';
        }
        break;
      case 'date':
        if (field.value) {
          const date = new Date(field.value);
          if (isNaN(date.getTime())) {
            isValid = false; errorMessage = 'Please enter a valid date.';
          }
        }
        break;
      case 'future-date':
        if (field.value) {
          const date = new Date(field.value);
          const today = new Date();
          if (date <= today) {
            isValid = false; errorMessage = 'Date must be in the future.';
          }
        }
        break;
    }
  }

  if (field.value) {
    if (isValid) {
      field.classList.add('is-valid');
    } else {
      field.classList.add('is-invalid');
      const feedback = field.parentNode.querySelector('.invalid-feedback');
      if (feedback) { feedback.textContent = errorMessage; }
    }
  }
  return isValid;
}

function clearValidationStates() {
  document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(input => {
    input.classList.remove('is-valid', 'is-invalid');
  });
}

// Form submit — AJAX POST → Odoo writes to employee record
document.getElementById('personalDetailsForm').addEventListener('submit', function(e) {
  e.preventDefault();

  const inputs = document.querySelectorAll('#personalDetailsForm input[data-validation], #personalDetailsForm select[data-validation]');
  let isFormValid = true;
  inputs.forEach(input => {
    if (!validateField({ target: input })) { isFormValid = false; }
  });

  if (!isFormValid) {
    showMessage('Please correct the errors in the form before submitting.', 'error');
    return;
  }

  const formData = new FormData(this);

  fetch('/my/employee/personal', {
    method: 'POST',
    body: formData
  })
  .then(response => response.json())
  .then(data => {
    if (data.success) {
      showMessage('Profile updated successfully!', 'success');
      disableEditMode();
      localStorage.removeItem('profileDraft');
      // Update last-updated timestamp display
      const ts = new Date().toLocaleString('en-GB', {
        day: '2-digit', month: 'short', year: 'numeric',
        hour: '2-digit', minute: '2-digit'
      });
      const el = document.querySelector('#viewActions strong');
      if (el) { el.textContent = ts; }
    } else {
      showMessage('Error: ' + (data.error || 'Unknown error'), 'error');
    }
  })
  .catch(error => {
    console.error('Error:', error);
    showMessage('Network error. Please try again.', 'error');
  });
});

function showMessage(text, type) {
  const messageContainer = document.getElementById('messageContainer');
  const successMsg = document.getElementById('successMessage');
  const errorMsg = document.getElementById('errorMessage');

  successMsg.style.display = 'none';
  errorMsg.style.display = 'none';
  successMsg.classList.remove('show');
  errorMsg.classList.remove('show');

  if (type === 'success') {
    document.getElementById('successText').textContent = text;
    successMsg.style.display = 'block';
    successMsg.classList.add('show');
  } else {
    document.getElementById('errorText').textContent = text;
    errorMsg.style.display = 'block';
    errorMsg.classList.add('show');
  }

  messageContainer.style.display = 'block';
  messageContainer.scrollIntoView({ behavior: 'smooth' });

  setTimeout(() => {
    successMsg.classList.remove('show');
    errorMsg.classList.remove('show');
  }, 5000);
}

// Load draft on page load
document.addEventListener('DOMContentLoaded', function() {
  const draftData = localStorage.getItem('profileDraft');
  if (draftData) {
    try {
      const draft = JSON.parse(draftData);
      Object.entries(draft).forEach(([key, value]) => {
        const input = document.querySelector(`[name="${key}"]`);
        if (input && input.type !== 'hidden') { input.value = value; }
      });
      showMessage('Draft data loaded. Continue editing or cancel to discard.', 'info');
    } catch (e) { console.error('Error loading draft:', e); }
  }
});
